import { createAsyncThunk, createSlice } from '@reduxjs/toolkit';
import type { RootState } from './index';

export type ActivityStatus = 'active' | 'inactive';
export type ConnectionStatus = 'connected' | 'disconnected';

export interface DeviceItem {
  id: number;
  code: string;
  name: string;
  ip: string;
  activityStatus: ActivityStatus;
  connectionStatus: ConnectionStatus;
  services: string[];
}

interface DevicesState {
  items: DeviceItem[];
  loading: boolean;
  error?: string;
}

const initialState: DevicesState = {
  items: [],
  loading: false,
  error: undefined,
};

const API_BASE = process.env.REACT_APP_API_URL || 'http://localhost:3001';

export const fetchDevices = createAsyncThunk<DeviceItem[]>('devices/fetchAll', async () => {
  const response = await fetch(`${API_BASE}/devices`);

  if (!response.ok) {
    throw new Error('Unable to load devices from mock API');
  }

  return (await response.json()) as DeviceItem[];
});

const devicesSlice = createSlice({
  name: 'devices',
  initialState,
  reducers: {},
  extraReducers: (builder) => {
    builder
      .addCase(fetchDevices.pending, (state) => {
        state.loading = true;
        state.error = undefined;
      })
      .addCase(fetchDevices.fulfilled, (state, action) => {
        state.loading = false;
        state.items = action.payload;
      })
      .addCase(fetchDevices.rejected, (state, action) => {
        state.loading = false;
        state.error = action.error.message || 'Failed to fetch devices';
      });
  },
});

export const selectDevices = (state: RootState) => state.devices.items;
export const selectDevicesLoading = (state: RootState) => state.devices.loading;
export const selectDevicesError = (state: RootState) => state.devices.error;

export default devicesSlice.reducer;
